class Solution {
    public String maximumBinaryString(String binary) {
        int zeros = 0, ones = 0;
        for (char c : binary.toCharArray()) {
            if (c == '0') zeros++;
            else ones++;
        }
        StringBuilder res = new StringBuilder();
        for (int i = 0; i < binary.length(); i++) {
            if (zeros > 0) {
                res.append('1');
                zeros--;
            } else {
                res.append('0');
            }
        }
        return res.toString();
    }
}
